var documenterSearchIndex = {"docs":
[{"category":"section","location":"guide/guide.html#Guide","page":"How to guide","text":"The [FinEtoolsFlexStructures] (https://github.com/PetrKryslUCSD/FinEtoolsFlexStructures.jl) package is used to solve static and dynamic linear and nonlinear  problems involving beams and linear static and dynamic analysis of shells.\n\nThe basic functionality is provided by the [FinEtools] (https://github.com/PetrKryslUCSD/FinEtools.jl) package.\n\nTutorials  are provided in the form of Julia scripts and Markdown files in a dedicated folder: index of tutorials. \n\nTo understand how the package works in depth, we would suggest inspecting the examples. The examples are organized by category: statics, dynamics, etc. There is usually an indication of what the correct answer should be (frequencies, deflections, buckling factors, ...). Many examples correspond to well-known benchmarks.","title":"Guide"},{"category":"section","location":"index.html#FinEtoolsFlexStructures-Documentation","page":"Home","text":"","title":"FinEtoolsFlexStructures Documentation"},{"category":"section","location":"index.html#Conceptual-guide","page":"Home","text":"The construction of the toolkit is described: the composition of modules, the basic data structures, the methodology of computing quantities required in the finite element methodology, and more.\n\nPages = [\n    \"guide/guide.md\",\n]\nDepth = 1","title":"Conceptual guide"},{"category":"section","location":"index.html#Manual","page":"Home","text":"The description of the types and the functions, organized by module and/or other logical principle.\n\nPages = [\n    \"man/man.md\",\n]\nDepth = 2","title":"Manual"},{"category":"section","location":"index.html#Index","page":"Home","text":"","title":"Index"},{"category":"section","location":"man/man.html#Manual","page":"Reference","text":"","title":"Manual"},{"category":"section","location":"man/man.html#Composite-Layup","page":"Reference","text":"","title":"Composite Layup"},{"category":"section","location":"man/man.html#Cross-Section","page":"Reference","text":"","title":"Cross Section"},{"category":"section","location":"man/man.html#Meshing-of-Frame-Members","page":"Reference","text":"","title":"Meshing of Frame Members"},{"category":"section","location":"man/man.html#FE-Set-for-two-node-Beams","page":"Reference","text":"","title":"FE Set for two-node Beams"},{"category":"section","location":"man/man.html#FE-Set-for-Shell-T3-shapes","page":"Reference","text":"","title":"FE Set for Shell T3 shapes"},{"category":"section","location":"man/man.html#FE-Set-for-Shell-Q4-shapes","page":"Reference","text":"","title":"FE Set for Shell Q4 shapes"},{"category":"section","location":"man/man.html#FEMM-for-Corotational-Beams","page":"Reference","text":"","title":"FEMM for Corotational Beams"},{"category":"section","location":"man/man.html#FEMM-for-linear-beams-with-eccentric-connections","page":"Reference","text":"","title":"FEMM for linear beams with eccentric connections"},{"category":"section","location":"man/man.html#FEMM-for-reduced-integration-Timoshenko-beams","page":"Reference","text":"","title":"FEMM for reduced-integration Timoshenko beams"},{"category":"section","location":"man/man.html#FEMM-for-Shell-T3FF-with-homogeneous-composition","page":"Reference","text":"","title":"FEMM for Shell T3FF with homogeneous composition"},{"category":"section","location":"man/man.html#FEMM-for-Shell-T3FF-with-layered-composition","page":"Reference","text":"","title":"FEMM for Shell T3FF with layered composition"},{"category":"section","location":"man/man.html#FEMM-for-Shell-Q4RS-with-homogeneous-composition","page":"Reference","text":"","title":"FEMM for Shell Q4RS with homogeneous composition"},{"category":"section","location":"man/man.html#FEMM-for-point-masses","page":"Reference","text":"","title":"FEMM for point masses"},{"category":"section","location":"man/man.html#FEMM-for-Grounded-springs","page":"Reference","text":"","title":"FEMM for Grounded springs"},{"category":"section","location":"man/man.html#Rotation-utilities","page":"Reference","text":"","title":"Rotation utilities"},{"category":"section","location":"man/man.html#Transformer-functions","page":"Reference","text":"","title":"Transformer functions"},{"category":"section","location":"man/man.html#Assembly-of-special-matrices","page":"Reference","text":"","title":"Assembly of special matrices"},{"category":"section","location":"man/man.html#Modules","page":"Reference","text":"","title":"Modules"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.cartesian_csys-Tuple{Any}","page":"Reference","text":"cartesian_csys(axes)\n\nCreate a material Cartesian coordinate system.\n\naxes = tuple of signed labels of the axes. For instance, (1, 2, 3) creates a coordinate system identical to the global cartesian coordinate system. (2, 1, -3) creates a coordinate system so that the first material basis vector is along the second global basis vector, the second material basis vector is along the first global basis vector, and the third material basis vector is opposite to the third global basis vector.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.cartesian_csys"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.lamina_material-NTuple{6, Any}","page":"Reference","text":"lamina_material(E1, E2, nu12, G12, G13, G23)\n\nCreate a transversely isotropic lamina material with default (zero) mass density.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.lamina_material"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.lamina_material-NTuple{7, Any}","page":"Reference","text":"lamina_material(rho, E1, E2, nu12, G12, G13, G23)\n\nCreate a transversely isotropic lamina material.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.lamina_material"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.lamina_material-Tuple{Any, Any, Any}","page":"Reference","text":"lamina_material(rho, E, nu)\n\nCreate an isotropic lamina material.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.lamina_material"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.lamina_material-Tuple{Any, Any}","page":"Reference","text":"lamina_material(E, nu)\n\nCreate an isotropic lamina material with default (zero) mass density.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.lamina_material"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.laminate_inertia!-Tuple{FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup}","page":"Reference","text":"laminate_inertia!(cl::CompositeLayup)\n\nCompute the laminate inertia.\n\nReturn the mass density and the moment of inertia density.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.laminate_inertia!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.laminate_stiffnesses!-Tuple{FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup, Any, Any, Any}","page":"Reference","text":"laminate_stiffnesses!(cl::CompositeLayup, A, B, D)\n\nCompute the laminate stiffness matrices, membrane, extension-bending coupling, and bending.\n\nA, B, and D are the familiar 3x3 matrices: Aij coefficients represent in-plane stiffness of the laminate, the Dij coefficients represent bending stiffness, the Bij represent bending-extension coupling.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.laminate_stiffnesses!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.laminate_transverse_stiffness!-Tuple{FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup, Any}","page":"Reference","text":"laminate_transverse_stiffness!(cl::CompositeLayup, H)\n\nCompute the laminate transverse stiffness.\n\nHij represent intralaminar shear stiffness.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.laminate_transverse_stiffness!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.plane_stress_T_matrix!-Union{Tuple{T}, Tuple{Matrix{T}, Any}} where T","page":"Reference","text":"plane_stress_T_matrix!(Tm::Array{T, 2}, angle) where {T}\n\nCompute the transformation matrix of stress vector components FROM the PLY coordinate system TO the LAYUP coordinate system.\n\nThe components of the stress vector transform as\n\nsigma = T  sigma^prime\n\nwhere sigma is the stress vector in the layup coordinate system, and sigma^prime is the stress vector in the ply coordinate system. \n\nArguments\n\nangle = angle (in radians) between the first basis vector of the layup     coordinate system and the first basis vector of the ply coordinate system m, n = cosine and sine of the angle\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.plane_stress_T_matrix!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.plane_stress_Tbar_matrix!-Union{Tuple{T}, Tuple{Matrix{T}, Any}} where T","page":"Reference","text":"plane_stress_Tbar_matrix!(Tm::Array{T, 2}, angle) where {T}\nplane_stress_Tbar_matrix!(Tm::Array{T, 2}, m, n) where {T}\n\nCompute the transformation matrix of engineering strain components FROM the LAYUP coordinate system TO the PLY coordinate system.\n\nThe components of the engineering strain vector transform as\n\nepsilon^prime = barT epsilon\n\nwhere epsilon is the engineering strain vector in the layup coordinate system, and epsilon^prime is the engineering strain vector in the ply coordinate system. \n\nFrom the work expression\n\nsigma^prime^T epsilon^prime = sigma^T epsilon\n\nwe conclude barT = T^-T.\n\nangle = angle (in radians) between the first basis vector of the layup     coordinate system and the first basis vector of the ply coordinate system m, n = cosine and sine of the angle\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.plane_stress_Tbar_matrix!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.plane_stress_Tinv_matrix!-Union{Tuple{T}, Tuple{Matrix{T}, Any}} where T","page":"Reference","text":"plane_stress_Tinv_matrix!(Tinvm::Array{T, 2}, angle) where {T}\nplane_stress_Tinv_matrix!(Tinvm::Array{T, 2}, m, n) where {T}\n\nCompute the transformation matrix of the stress vector components FROM the LAYUP coordinate system TO the PLY coordinate system.\n\nThe components of the stress vector transform as\n\nsigma^prime = T^-1 sigma\n\nwhere sigma is the stress vector in the layup coordinate system, and sigma^prime is the stress vector in the ply coordinate system. \n\nangle = angle (in radians) between the first basis vector of the layup     coordinate system and the first basis vector of the ply coordinate system m, n = cosine and sine of the angle\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.plane_stress_Tinv_matrix!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.thickness-Tuple{FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup}","page":"Reference","text":"thickness(cl::CompositeLayup)\n\nCompute the thickness of the layup (sum of the thicknesses of the plies).\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.thickness"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.transverse_shear_T_matrix!-Union{Tuple{T}, Tuple{Matrix{T}, Any}} where T","page":"Reference","text":"transverse_shear_T_matrix!(Tm::Array{T, 2}, angle) where {T}\ntransverse_shear_T_matrix!(Tm::Array{T, 2}, m, n) where {T}\n\nCompute the transformation matrix for the transverse shear stresses  FROM the LAYUP coordinate system TO the PLY coordinate system.\n\nangle = angle (in radians) between the first basis vector of the layup     coordinate system and the first basis vector of the ply coordinate system m, n = cosine and sine of the angle\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.transverse_shear_T_matrix!"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup","page":"Reference","text":"CompositeLayup\n\nType for composite layup.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup-Tuple{Any, Any, Any}","page":"Reference","text":"CompositeLayup(name, plies, mcsys)\n\nCreate a composite layup.\n\nProvide the name, the array of plies (Ply), and the coordinate system that defines the orientation of the composite layup. The first base vector of this coordinate system is the reference direction for the layup. The transverse shear model is TransverseShearModelVinsonSierakowski().\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup-Union{Tuple{N}, Tuple{Any, Any, Any, N}} where N<:Number","page":"Reference","text":"CompositeLayup(name, plies, mcsys, tcf)\n\nCreate a composite layup.\n\nProvide the name, the array of plies (Ply), the coordinate system that defines the orientation of the composite layup (the first base vector  of this coordinate system is the reference direction for the layup),  and the transverse shear correction constant.  The transverse shear model is TransverseShearModelConstant().\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.Ply","page":"Reference","text":"Ply{M} <: AbstractPly\n\nType of a ply.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.Ply"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule.Ply-Union{Tuple{M}, Tuple{Any, M, Any, Any}} where M","page":"Reference","text":"Ply(name, material::M, thickness, angle) where {M}\n\nCreate a ply.\n\nProvide name, material of the ply, thickness of the ply, an angle between the first bases vector of the layup coordinate system and the first direction of the ply material coordinate system.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule.Ply"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CrossSectionModule.CrossSectionCircle-Tuple{Any, Any, Any}","page":"Reference","text":"CrossSectionCircle(radius, x1x2_vector, shear_resisting_area_factor = 6/7; label = 0)\n\nCreate a circular section for use with a Timoshenko model.\n\nCommonly accepted value is shear_resisting_area_factor = 6/7.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CrossSectionModule.CrossSectionCircle"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CrossSectionModule.CrossSectionCircle-Tuple{Any, Any}","page":"Reference","text":"CrossSectionCircle(radius, x1x2_vector; label = 0)\n\nCreate a circular section for use with a Bernoulli model.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CrossSectionModule.CrossSectionCircle"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CrossSectionModule.CrossSectionRectangle-NTuple{4, Any}","page":"Reference","text":"CrossSectionRectangle(d2f, d3f, x1x2_vector; label = 0)\n\nCreate a rectangular section for use with a Timoshenko model.\n\nCommonly accepted value is shear_resisting_area_factor = 5/6.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CrossSectionModule.CrossSectionRectangle"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.CrossSectionModule.CrossSectionRectangle-Tuple{Any, Any, Any}","page":"Reference","text":"CrossSectionRectangle(d2f, d3f, x1x2_vector; label = 0)\n\nCreate a rectangular section for use with a Bernoulli model.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CrossSectionModule.CrossSectionRectangle"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.MeshFrameMemberModule.frame_member-Tuple{Any, Any, Any}","page":"Reference","text":"frame_member(xyz, nL, crosssection; label = 0)\n\nMesh of a generally curved beam member given by the location of the vertices of the spline curve.\n\nxyz = array of vertex locations, one vertex per row nL = number of elements\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.MeshFrameMemberModule.frame_member"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.MeshFrameMemberModule.fuse_members-Tuple{Any}","page":"Reference","text":"fuse_members(members; tolerance = 0.001)\n\nFuse members by merging the meshes for the members.\n\nComputes an array of meshes.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.MeshFrameMemberModule.fuse_members"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.MeshFrameMemberModule.merge_members-Tuple{Any}","page":"Reference","text":"merge_members(members; tolerance = 0.001)\n\nMerge together meshes of the members.\n\nUses fuse_members to merge the nodes, then concatenates the finite elements.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.MeshFrameMemberModule.merge_members"},{"category":"method","location":"man/man.html#Base.cat-Union{Tuple{T}, Tuple{T, T}} where T<:FinEtoolsFlexStructures.FESetL2BeamModule.FESetL2Beam","page":"Reference","text":"cat(self::T,  other::T) where {T<:FESetL2Beam}\n\nConcatenate two sets of beam elements.\n\n\n\n\n\n","title":"Base.cat"},{"category":"method","location":"man/man.html#FinEtools.FESetModule.subset-Union{Tuple{IT}, Tuple{T}, Tuple{T, IT}} where {T<:FinEtoolsFlexStructures.FESetL2BeamModule.FESetL2Beam, IT}","page":"Reference","text":"subset(self::T, L::IT) where {T<:FESetL2Beam, IT}\n\nSubset of a beam-element set.\n\n\n\n\n\n","title":"FinEtools.FESetModule.subset"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FESetL2BeamModule.FESetL2Beam","page":"Reference","text":"mutable struct FESetL2Beam{CT} <: AbstractFESet1Manifold{2}\n\nType of a two-node beam finite element set.\n\nThe elements in the set have the same cross section type, but since the cross section dimensions may depend on the coordinate, each individual element may have a different area, second moments of area, etc.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetL2BeamModule.FESetL2Beam"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FESetL2BeamModule.FESetL2Beam-Union{Tuple{CT}, Tuple{IT}, Tuple{IT, CT}} where {IT<:Integer, CT}","page":"Reference","text":"FESetL2Beam(N::IT, crosssection::CT) where {IT<:Integer, CT}\n\nConstructor.\n\nSupply the total number of elements in the set, and the cross-section definition. The parameters of the section are assumed to be uniform along the set of the beam elements.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetL2BeamModule.FESetL2Beam"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FESetShellT3Module.FESetShellT3","page":"Reference","text":"struct FESetShellT3 <: AbstractFESet2Manifold{3}\n\nType of a finite element set for the three-node shell.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetShellT3Module.FESetShellT3"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FESetShellQ4Module.FESetShellQ4","page":"Reference","text":"struct FESetShellQ4 <: AbstractFESet2Manifold{4}\n\nType of a finite element set for the four-node quadrilateral shell.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetShellQ4Module.FESetShellQ4"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.current_local_frame!-NTuple{4, Any}","page":"Reference","text":"current_local_frame!(Ft, xt, FtI, FtJ)\n\nCompute the current local frame from the positions of the nodes and the orientation matrices (frames) at the nodes.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.current_local_frame!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.distribloads_global-Union{Tuple{TI}, Tuple{T}, Tuple{GFT}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam, ASS, FinEtools.NodalFieldModule.NodalField{GFT}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}, Any}} where {ASS<:FinEtools.AssemblyModule.AbstractSysvecAssembler, GFT<:Number, T<:Number, TI<:Number}","page":"Reference","text":"distribloads_global(self::FEMMCorotBeam, assembler::ASS, geom0::NodalField{GFT}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{TI}, fi) where {ASS<:AbstractSysvecAssembler, GFT<:Number, T<:Number, TI<:Number}\n\nCompute the load vector due to distributed loads.\n\nCompute the global load vector corresponding to applied distributed load. Here it means force per unit length of the beam, in the configuration u1, Rfield1. These are only forces, not moments.\n\nnote: Note\nThe force intensity must be uniform across the entire element. The force intensity is given in the global coordinates.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.distribloads_global"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.geostiffness-Union{Tuple{TI}, Tuple{T}, Tuple{GFT}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam, ASS, FinEtools.NodalFieldModule.NodalField{GFT}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}","page":"Reference","text":"geostiffness(self::FEMMCorotBeam, assembler::ASS, geom0::NodalField{GFT}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{TI}) where {ASS<:AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}\n\nCompute the geometric stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.geostiffness"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.gyroscopic-Union{Tuple{TI}, Tuple{T}, Tuple{GFT}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam, ASS, FinEtools.NodalFieldModule.NodalField{GFT}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}","page":"Reference","text":"gyroscopic(self::FEMMCorotBeam, assembler::ASS, geom0::NodalField{GFT}, u1::NodalField{T}, Rfield1::NodalField{T}, v1::NodalField{T}, dchi::NodalField{TI}; mass_type=MASS_TYPE_CONSISTENT_WITH_ROTATION_INERTIA) where {ASS<:AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}\n\nCompute the quadratic-inertial-term (gyroscopic) mass matrix\n\nThis is a general routine for the abstract linear-deformation  FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.gyroscopic"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.local_cartesian_to_natural!-Tuple{Any, Any}","page":"Reference","text":"local_cartesian_to_natural!(aN, L)\n\nCompute transformation from local Cartesian displacements to natural deformations of a beam element.\n\nMatrix defined in Eq (4.8) of COMPUTER  METHODS  IN APPLIED  MECHANICS  AND  ENGINEERING   14  (1978)  401-451 ON LARGE  DISPLACEMENT-SMALL   STRAIN  ANALYSIS   OF  STRUCTURES WITH  ROTATIONAL   DEGREES  OF  FREEDOM. J.H.  ARGYRIS,   P.C.  DUNNE  and  D.W. SCHARPF\n\nArguments\n\nL= current length of the element\n\nOutputs\n\naN= transformation matrix to take Cartesian (local) displacement increments in the      element frame and to produce increments of natural deformations;      see local_frame_and_def! for the definition of the natural deformations\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.local_cartesian_to_natural!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.local_forces!-NTuple{4, Any}","page":"Reference","text":"local_forces!(FL, PN, L, aN)\n\nCompute forces through which the element acts on the nodes in the local coordinate system.\n\nArguments\n\nPN = column vector of natural forces; L= current length of the element, aN= transformation matrix to take Cartesian (local) displacement increments in the      element frame and to produce increments of natural deformations;      see local_frame_and_def! for the definition of the natural deformations\n\nOutputs\n\nFL = vector of forces acting on the nodes in the local coordinate system\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.local_forces!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.local_frame_and_def!-NTuple{10, Any}","page":"Reference","text":"local_frame_and_def!(Ft, dN, F0, FtI, FtJ, x0, x1x2_vector, xt, RI, RJ)\n\nCompute the current length of the element, the current element frame, and the natural deformations\n\nArguments\n\nx0= array of node coordinates, one node per row, in initial configuration x1x2_vector= vector that lies in the x1-x2 local element coordinate      plane, in initial configuration xt= array of node coordinates, one node per row, in initial configuration RI,RJ=nodal rotation (orthogonal) matrix\n\nOutputs\n\nLt= current length of the element, Ft= current element frame (orthogonal rotation matrix) whose columns are unit      vectors: they are centered halfway between the current locations of      the nodes, vector 1 points from node I to node J, vector 3 is      orthogonal to the sum of the nodal cross-section frame vectors 2 dN= vector of natural deformations; dN(1)= total change in length      between configurations 0 and t; dN(2)= symmetric bending;      dN(3)= anti-symmetric bending;    dN(4)= symmetric bending      dN(5)= anti-symmetric bending; dN(6)=total axial torsion angle.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.local_frame_and_def!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.local_geometric_stiffness!-NTuple{6, Any}","page":"Reference","text":"local_geometric_stiffness!(SM, A, I2, I3, PN, L)\n\nCompute the local geometric stiffness matrix.\n\nArguments\n\nA= cross-sectional area, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, PN= vector of natural forces; see natural_forces() for definitions L= current length of the element,\n\nOutputs\n\nSM = local geometric stiffness matrix, 12 x 12\n\nThis geometric stiffness matrix this consistent with relationship between the natural deformations and the natural forces that assumes there is only a linear constitutive link: no non-constitutive effects (bowing etc.) are included. This form of the geometric matrix was derived by Krenk. @BOOK{Krenk:2009,   AUTHOR =       {S. Krenk},   TITLE =        {Non-linear Modeling and Analysis of Solids and Structures },   PUBLISHER =    {Cambridge University Press},   YEAR =         {2009},   isbn =         {9780521830546} }\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.local_geometric_stiffness!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.local_mass!-NTuple{8, Any}","page":"Reference","text":"local_mass!(MM, A, I1, I2, I3, rho, L, mass_type)\n\nMass matrix of the beam.\n\nArguments\n\nA= cross-sectional area, I1=central moment of inertia of the cross-section about the x1 axis, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, rho=mass density, L= initial length of the element,\n\nOutputs\n\nMM = local mass matrix, 12 x 12 In the element frame the mass matrix is constant.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.local_mass!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.local_stiffness!-NTuple{12, Any}","page":"Reference","text":"local_stiffness!(SM, E, G, A, I2, I3, J, A2s, A3s, L, aN, DN)\n\nCompute the local elastic stiffness matrix.\n\nArguments\n\nE, G= Young's and shear modulus, A= cross-sectional area, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, J=St Venant torsion constant, L= current length of the element,\n\nOutputs\n\nSM = local stiffness matrix, 12 x 12\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.local_stiffness!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.mass-Union{Tuple{TI}, Tuple{T}, Tuple{GFT}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam, ASS, FinEtools.NodalFieldModule.NodalField{GFT}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}","page":"Reference","text":"mass(self::FEMMCorotBeam, assembler::ASS, geom0::NodalField{GFT}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{TI}; mass_type=MASS_TYPE_CONSISTENT_WITH_ROTATION_INERTIA) where {ASS<:AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}\n\nCompute the consistent mass matrix\n\nThis is a general routine for the abstract linear-deformation  FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.mass"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.natural_forces!-NTuple{12, Any}","page":"Reference","text":"natural_forces!(PN, E, G, A, I2, I3, J, A2s, A3s, L, dN, DN)\n\nCompute the natural forces from the natural deformations.\n\nArgument\n\nE, G= Young's and shear modulus, A= cross-sectional area, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, J=St Venant torsion constant, L= current length of the element, dN= column vector of natural deformations; see local_frames()\n\nOutputs\n\nPN = column vector of natural forces;      PN[1]= axial force;      PN[2]= symmetric bending moment in the plane x1-x2;      PN[3]= anti-symmetric bending bending moment in the plane x1-x2;      PN[4]= symmetric bending bending moment in the plane x1-x3;      PN[5]= anti-symmetric bending bending moment in the plane x1-x3;      PN[6]= axial torque.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.natural_forces!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.natural_stiffness_Bernoulli!-NTuple{10, Any}","page":"Reference","text":"natural_stiffness_Bernoulli!(DN, E, G, A, I2, I3, J, A2s, A3s, L)\n\nCompute the natural stiffness matrix.\n\nfunction DN = natural_stiffness(self, E, G, A, I2, I3, J, L)\n\nArguments\n\nE, G= Young's and shear modulus,\nA= cross-sectional area,\nI2, I3= central moment of inertia of the cross-section about the x2 and x3 coordinate axis,\nJ= St Venant torsion constant,\nA2s = effective area for shear in the direction of x2 (ignored)\nA3s = effective area for shear in the direction of x3 (ignored)\nL= current length of the element,\n\nOutputs\n\nDN = 6 x 6 natural stiffness matrix\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.natural_stiffness_Bernoulli!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.natural_stiffness_Timoshenko!-NTuple{10, Any}","page":"Reference","text":"natural_stiffness_Timoshenko!(DN, E, G, A, I2, I3, J, A2s, A3s, L)\n\nCompute the natural stiffness matrix.\n\nfunction DN = natural_stiffness(self, E, G, A, I2, I3, J, L)\n\nArguments\n\nE, G= Young's and shear modulus,\nA= cross-sectional area,\nI2, I3= central moment of inertia of the cross-section about the x2 and x3 coordinate axis,\nJ= St Venant torsion constant,\nA2s = effective area for shear in the direction of x2\nA3s = effective area for shear in the direction of x3\nL= current length of the element,\n\nOutputs\n\nDN = 6 x 6 natural stiffness matrix\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.natural_stiffness_Timoshenko!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.restoringforce-Union{Tuple{TI}, Tuple{T}, Tuple{GFT}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam, ASS, FinEtools.NodalFieldModule.NodalField{GFT}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysvecAssembler, GFT<:Number, T<:Number, TI<:Number}","page":"Reference","text":"restoringforce(self::FEMMCorotBeam, assembler::ASS, geom0::NodalField{GFT}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{TI}) where {ASS<:AbstractSysvecAssembler, GFT<:Number, T<:Number, TI<:Number}\n\nCompute the vector of the restoring elastic forces\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.restoringforce"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.stiffness-Union{Tuple{TI}, Tuple{T}, Tuple{GFT}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam, ASS, FinEtools.NodalFieldModule.NodalField{GFT}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}","page":"Reference","text":"stiffness(self::FEMMCorotBeam, assembler::ASS, geom0::NodalField{GFT}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{TI}) where {ASS<:AbstractSysmatAssembler, GFT<:Number, T<:Number, TI<:Number}\n\nCompute the material stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam","page":"Reference","text":"mutable struct FEMMCorotBeam{ID<:IntegDomain{S} where {S<:FESetL2}, M<:MatDeforElastIso} <: AbstractFEMM\n\nType for co-rotational beam finite element modeling machine (FEMM).\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam-Union{Tuple{M}, Tuple{ID}, Tuple{ID, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetL2), M<:FinEtoolsDeforLinear.MatDeforElastIsoModule.MatDeforElastIso}","page":"Reference","text":"FEMMCorotBeam(integdomain::IntegDomain{S, F}, material::MatDeforElastIso) where {S<:FESetL2, F<:Function}\n\nConstructor.\n\nSupply the integration domain and the material.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.FEMMCorotBeam"},{"category":"constant","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule.MASS_TYPE_CONSISTENT_NO_ROTATION_INERTIA","page":"Reference","text":"Type of the mass matrix formulation.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule.MASS_TYPE_CONSISTENT_NO_ROTATION_INERTIA"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.inspectintegpoints-Union{Tuple{F}, Tuple{IT}, Tuple{FT}, Tuple{FEMM}, Tuple{FEMM, FinEtools.NodalFieldModule.NodalField{FT}, FinEtools.NodalFieldModule.NodalField{FT}, FinEtools.NodalFieldModule.NodalField{FT}, AbstractVector{IT}, F, Any}, Tuple{FEMM, FinEtools.NodalFieldModule.NodalField{FT}, FinEtools.NodalFieldModule.NodalField{FT}, FinEtools.NodalFieldModule.NodalField{FT}, AbstractVector{IT}, F, Any, Any}} where {FEMM<:FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam, FT, IT, F<:Function}","page":"Reference","text":"inspectintegpoints(\n    self::FEMM,\n    geom::NodalField{FT},\n    felist::AbstractVector{IT},\n    inspector::F,\n    idat,\n    quantity = :Cauchy;\n    context...,\n) where {FEMM<:AbstractFEMM, FT, IT, F<:Function}\n\nInspect integration points.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.inspectintegpoints"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.distribloads_global-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}, Any}} where {ASS<:FinEtools.AssemblyModule.AbstractSysvecAssembler, T<:Number, TI<:Number}","page":"Reference","text":"distribloads_global(self::FEMMLinBeam, geom0::NodalField{FFlt}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{T}, fi) where {T<:Number}\n\nCompute the load vector due to distributed loads.\n\nCompute the global load vector corresponding to applied distributed load. Here it means force per unit length of the beam, in the configuration u1, Rfield1. These are only forces, not moments.\n\nnote: Note\nThe force intensity must be uniform across the entire element. The force intensity is given in the global coordinates.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.distribloads_global"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.local_cartesian_to_natural!-Tuple{Any, Any}","page":"Reference","text":"local_cartesian_to_natural!(aN, L)\n\nCompute transformation from local Cartesian displacements to natural deformations of a beam element.\n\nMatrix defined in Eq (4.8) of COMPUTER  METHODS  IN APPLIED  MECHANICS  AND  ENGINEERING   14  (1978)  401-451 ON LARGE  DISPLACEMENT-SMALL   STRAIN  ANALYSIS   OF  STRUCTURES WITH  ROTATIONAL   DEGREES  OF  FREEDOM. J.H.  ARGYRIS,   P.C.  DUNNE  and  D.W. SCHARPF\n\nArguments\n\nL= current length of the element\n\nOutputs\n\naN= transformation matrix to take Cartesian (local) displacement increments in the      element frame and to produce increments of natural deformations;      see local_frame_and_def! for the definition of the natural deformations\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.local_cartesian_to_natural!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.local_forces!-NTuple{4, Any}","page":"Reference","text":"local_forces!(FL, PN, L, aN)\n\nCompute forces through which the element acts on the nodes in the local coordinate system.\n\nArguments\n\nPN = column vector of natural forces; L= current length of the element, aN= transformation matrix to take Cartesian (local) displacement increments in the      element frame and to produce increments of natural deformations;      see local_frame_and_def! for the definition of the natural deformations\n\nOutputs\n\nFL = vector of forces acting on the nodes in the local coordinate system\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.local_forces!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.local_mass!-NTuple{8, Any}","page":"Reference","text":"local_mass!(MM, A, I1, I2, I3, rho, L, mass_type)\n\nMass matrix of the beam.\n\nArguments\n\nA= cross-sectional area, I1=central moment of inertia of the cross-section about the x1 axis, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, rho=mass density, L= initial length of the element,\n\nOutputs\n\nMM = local mass matrix, 12 x 12 In the element frame the mass matrix is constant.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.local_mass!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.local_stiffness!-NTuple{12, Any}","page":"Reference","text":"local_stiffness!(SM, E, G, A, I2, I3, J, A2s, A3s, L, aN, DN)\n\nCompute the local elastic stiffness matrix.\n\nArguments\n\nE, G= Young's and shear modulus, A= cross-sectional area, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, J=St Venant torsion constant, L= current length of the element,\n\nOutputs\n\nSM = local stiffness matrix, 12 x 12\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.local_stiffness!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.mass-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, T<:Number, TI<:Number}","page":"Reference","text":"mass(self::FEMMLinBeam,  assembler::A,\n  geom::NodalField{FFlt},\n  u::NodalField{T}) where {A<:AbstractSysmatAssembler, T<:Number}\n\nCompute the consistent mass matrix\n\nThis is a general routine for the abstract linear-deformation  FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.mass"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.natural_forces!-NTuple{12, Any}","page":"Reference","text":"natural_forces!(PN, E, G, A, I2, I3, J, A2s, A3s, L, dN, DN)\n\nCompute the natural forces from the natural deformations.\n\nArgument\n\nE, G= Young's and shear modulus, A= cross-sectional area, I2, I3=central moment of inertia of the cross-section about the x2 and x3 coordinate axis, J=St Venant torsion constant, L= current length of the element, dN= column vector of natural deformations; see local_frames()\n\nOutputs\n\nPN = column vector of natural forces;      PN[1]= axial force;      PN[2]= symmetric bending moment in the plane x1-x2;      PN[3]= anti-symmetric bending bending moment in the plane x1-x2;      PN[4]= symmetric bending bending moment in the plane x1-x3;      PN[5]= anti-symmetric bending bending moment in the plane x1-x3;      PN[6]= axial torque.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.natural_forces!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.natural_stiffness_Bernoulli!-NTuple{10, Any}","page":"Reference","text":"natural_stiffness_Bernoulli!(DN, E, G, A, I2, I3, J, A2s, A3s, L)\n\nCompute the natural stiffness matrix.\n\nfunction DN = natural_stiffness(self, E, G, A, I2, I3, J, L)\n\nArguments\n\nE, G= Young's and shear modulus,\nA= cross-sectional area,\nI2, I3= central moment of inertia of the cross-section about the x2 and x3 coordinate axis,\nJ= St Venant torsion constant,\nA2s = effective area for shear in the direction of x2 (ignored)\nA3s = effective area for shear in the direction of x3 (ignored)\nL= current length of the element,\n\nOutputs\n\nDN = 6 x 6 natural stiffness matrix\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.natural_stiffness_Bernoulli!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.natural_stiffness_Timoshenko!-NTuple{10, Any}","page":"Reference","text":"natural_stiffness_Timoshenko!(DN, E, G, A, I2, I3, J, A2s, A3s, L)\n\nCompute the natural stiffness matrix.\n\nfunction DN = natural_stiffness(self, E, G, A, I2, I3, J, L)\n\nArguments\n\nE, G= Young's and shear modulus,\nA= cross-sectional area,\nI2, I3= central moment of inertia of the cross-section about the x2 and x3 coordinate axis,\nJ= St Venant torsion constant,\nA2s = effective area for shear in the direction of x2\nA3s = effective area for shear in the direction of x3\nL= current length of the element,\n\nOutputs\n\nDN = 6 x 6 natural stiffness matrix\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.natural_stiffness_Timoshenko!"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.stiffness-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, T<:Number, TI<:Number}","page":"Reference","text":"stiffness(self::FEMMLinBeam, assembler::ASS, geom0::NodalField{FFlt}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{T}) where {ASS<:AbstractSysmatAssembler, T<:Number}\n\nCompute the material stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam","page":"Reference","text":"mutable struct FEMMLinBeam{ID<:IntegDomain{S} where {S<:FESetL2}, M<:MatDeforElastIso} <: AbstractFEMM\n\nType for linear beam finite element modeling machine.\n\nThe beam can be connected to the nodes with given eccentricities (the transverse eccentricity is uniform along its length). Only linear kinematics is implemented at the moment. The beam stiffness can be either shear-flexible (Timoshenko), or shear-rigid (Bernoulli-Euler). The local beam stiffness is expressed analytically: no numerical integration is involved.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam-Union{Tuple{M}, Tuple{ID}, Tuple{ID, M, Any}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetL2), M<:FinEtoolsDeforLinear.MatDeforElastIsoModule.MatDeforElastIso}","page":"Reference","text":"FEMMLinBeam(\n    integdomain::ID,\n    material::M,\n    uniform_eccentricity,\n) where {ID<:IntegDomain{S} where {S<:FESetL2}, M<:MatDeforElastIso}\n\nConstructor.\n\nSupply the integration domain, material, and the eccentricity parameters (given in the order: first node, f1 direction, second node, f1 direction, f2 direction, f3 direction).\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam-Union{Tuple{M}, Tuple{ID}, Tuple{ID, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetL2), M<:FinEtoolsDeforLinear.MatDeforElastIsoModule.MatDeforElastIso}","page":"Reference","text":"FEMMLinBeam(\n    integdomain::ID,\n    material::M,\n) where {ID<:IntegDomain{S} where {S<:FESetL2}, M<:MatDeforElastIso}\n\nConstructor.\n\nSupply the integration domain and the material. The eccentricities are assumed to be zero.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.FEMMLinBeam"},{"category":"constant","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule.MASS_TYPE_CONSISTENT_NO_ROTATION_INERTIA","page":"Reference","text":"Type of the mass matrix formulation.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule.MASS_TYPE_CONSISTENT_NO_ROTATION_INERTIA"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMRITBeamModule.distribloads_global-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMRITBeamModule.FEMMRITBeam, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}, Any}} where {ASS<:FinEtools.AssemblyModule.AbstractSysvecAssembler, T<:Number, TI<:Number}","page":"Reference","text":"distribloads_global(self::FEMMRITBeam, geom0::NodalField{FFlt}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{T}, fi) where {T<:Number}\n\nCompute the load vector due to distributed loads.\n\nCompute the global load vector corresponding to applied distributed load. Here it means force per unit length of the beam, in the configuration u1, Rfield1. These are only forces, not moments.\n\nnote: Note\nThe force intensity must be uniform across the entire element. The force intensity is given in the global coordinates.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMRITBeamModule.distribloads_global"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMRITBeamModule.stiffness-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMRITBeamModule.FEMMRITBeam, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, T<:Number, TI<:Number}","page":"Reference","text":"stiffness(self::FEMMRITBeam, assembler::ASS, geom0::NodalField{FFlt}, u1::NodalField{T}, Rfield1::NodalField{T}, dchi::NodalField{T}) where {ASS<:AbstractSysmatAssembler, T<:Number}\n\nCompute the material stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMRITBeamModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMRITBeamModule.FEMMRITBeam","page":"Reference","text":"mutable struct FEMMRITBeam{ID<:IntegDomain{S} where {S<:FESetL2}, M<:MatDeforElastIso} <: AbstractFEMM\n\nType for linear reduced-integration beam finite element modeling machine.\n\nOnly linear kinematics is implemented at the moment, and only linear basis functions are available (i.e. it is a two-node element). The beam stiffness is shear-flexible (Timoshenko). The local beam stiffness is expressed analytically: the one-point numerical integration is hardwired.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMRITBeamModule.FEMMRITBeam"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMRITBeamModule.FEMMRITBeam-Union{Tuple{M}, Tuple{ID}, Tuple{ID, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetL2), M<:FinEtoolsDeforLinear.MatDeforElastIsoModule.MatDeforElastIso}","page":"Reference","text":"FEMMRITBeam(\n    integdomain::ID,\n    material::M,\n) where {ID<:IntegDomain{S} where {S<:FESetL2}, M<:MatDeforElastIso}\n\nConstructor.\n\nSupply integration domain (mesh) and the material.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMRITBeamModule.FEMMRITBeam"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.associategeometry!-Tuple{FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF, FinEtools.NodalFieldModule.NodalField{Float64}}","page":"Reference","text":"associategeometry!(self::FEMMShellT3FF,  geom::NodalField{FFlt})\n\nAssociate geometry with the FEMM. \n\nIn this case it means evaluate the nodal normals.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.associategeometry!"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.inspectintegpoints-Union{Tuple{F}, Tuple{TI}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{Float64}, Vector{Int64}, F, Any}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{Float64}, Vector{Int64}, F, Any, Any}} where {TI<:Number, F<:Function}","page":"Reference","text":"inspectintegpoints(self::AbstractFEMMDeforLinear,\n  geom::NodalField{FFlt},  u::NodalField{TI},\n  dT::NodalField{FFlt},\n  felist::FIntVec,\n  inspector::F,  idat, quantity=:Cauchy;\n  context...) where {TI<:Number, F<:Function}\n\nInspect integration point quantities.\n\ngeom - reference geometry field\nu - displacement+rotation field\ndT - temperature difference field\nfelist - indexes of the finite elements that are to be inspected:    The fes to be included are: fes[felist].\ncontext    - structure: see the update!() method of the material.\ninspector - function with the signature       idat = inspector(idat, j, conn, x, out, loc);  where   idat - a structure or an array that the inspector may          use to maintain some state,  for instance minimum or maximum of          stress, j is the element number, conn is the element connectivity,          out is the output of the update!() method,  loc is the location          of the integration point in the reference configuration.\n\nReturn\n\nThe updated inspector data is returned.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.inspectintegpoints"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.make-Tuple{Any, Any, Any}","page":"Reference","text":"make(integdomain, mcsys, material)\n\nMake a T3FF FEMM from the integration domain, a coordinate system to define the orientation of the normals, and a material.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.make"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.make-Tuple{Any, Any}","page":"Reference","text":"make(integdomain, material)\n\nMake a T3FF FEMM from the integration domain,  and a material. Default isoparametric method for computing the normals is used.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.make"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.mass-Union{Tuple{TI}, Tuple{A}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF, A, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}}} where {A<:FinEtools.AssemblyModule.AbstractSysmatAssembler, TI<:Number}","page":"Reference","text":"mass(self::FEMMShellT3FF,  assembler::A,  geom::NodalField{FFlt}, dchi::NodalField{TI}) where {A<:AbstractSysmatAssembler, TI<:Number}\n\nCompute the diagonal (lumped) mass matrix\n\nThe mass matrix can be expected to be non-singular.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.mass"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.num_normals-Tuple{FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF}","page":"Reference","text":"num_normals(self::FEMMShellT3FF)\n\nCompute the summary of the nodal normals.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.num_normals"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.stiffness-Union{Tuple{TI}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, TI<:Number}","page":"Reference","text":"stiffness(self::FEMMShellT3FF, assembler::ASS, geom0::NodalField{FFlt}, u1::NodalField{TI}, Rfield1::NodalField{TI}, dchi::NodalField{TI}) where {ASS<:AbstractSysmatAssembler, TI<:Number}\n\nCompute the material stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF","page":"Reference","text":"mutable struct FEMMShellT3FF{ID<:IntegDomain{S} where {S<:FESetT3}, T<:Real, CS<:CSys{T}, M} <: AbstractFEMM\n\nType for the finite element modeling machine of the T3 triangular Flat-Facet shell with the Discrete Shear Gap technology and a consistent handling of the normals. \n\nWith averaging of the transverse strain-displacement matrix or averaging of the transverse shear stiffness matrix to provide isotropic transverse shear response. \n\nAlso, the formulation is developed to correctly handle the coupling of twisting moments and transverse shear (such as in the twisted beam or the Raasch hook problems) by incorporating \"nodal\" normals.\n\nSome of the programming developed consistently with the paper\n\n[1] Cui et al, Analysis of plates and shells using an edge-based smoothed finite element method, Comput Mech (2010) 45:141–156 DOI 10.1007/s00466-009-0429-9\n\nThe stabilization factor of the shear term of\n\n[2] Mikko Lyly, Rolf Stenberg and Teemu Vihinen, A stable bilinear element for the Reissner-Mindlin plate model Computer Methods in Applied Mechanics and Engineering 110 (1993) 343-357 \n\nis incorporated. Refer to expressions (3.12) and (3.13).\n\nThe treatment of the transformation between the element and nodal coordinates is carried out using a clean alternative to the publication\n\n[3] Finite Elements in Analysis and Design 30 (1998) 235—242 The treatment of shell normals in finite element analysis Richard H. MacNeal, Charles T. Wilson, Robert L. Harder, Claus C. Hoﬀ The MacNeal-Schwendler Corporation, 815 Colorado Blvd., Los Angeles, CA 90041, USA\n\nThe formula for the element to nodal basis transformation is derived from the expression\n\n[theta]_n = [A]_E^T [theta]_e + [A_3,1:3]_E^T [alpha_3]_e\n\nby disconnecting the drilling degree of freedom from the bending degrees of freedom in the nodal basis.\n\nThe following features are incorporated to deal with nodal normals:\n\nNodal normals are averages of the normals of elements that meet at a node.\nA crease in the surface is taken into account. In that case the normal are not averaged across the crease. At the nodes along the crease every element uses the normal to its surface instead of the nodal normal.\n\nConfiguration:\n\nThese attributes of the FEMM can be set after it's been created.\n\ntransv_shear_formulation: which formulation for the transverse shear stiffness? \nFEMMShellT3FFModule.__TRANSV_SHEAR_FORMULATION_AVERAGE_B - averaged strains (default)\nFEMMShellT3FFModule.__TRANSV_SHEAR_FORMULATION_AVERAGE_K - averaged stiffness\ndrilling_stiffness_scale: multiplier of the generalized stiffness coefficient\nthreshold_angle: angle in degrees. If a nodal normal subtends angle bigger then this threshold, the nodal normal at that note is marked as invalid.\nmult_el_size: multiplier of the square of the element size, used to control transverse shear stiffness.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF-Union{Tuple{M}, Tuple{CS}, Tuple{T}, Tuple{ID}, Tuple{ID, CS, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetT3), T<:Real, CS<:(FinEtools.CSysModule.CSys{T}), M}","page":"Reference","text":"FEMMShellT3FF(\n    integdomain::ID,\n    mcsys::CSys,\n    material::M,\n) where {IntegDomain{S} where {S<:FESetT3}, CS<:CSys, M}\n\nConstructor of the T3FF shell FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF-Union{Tuple{M}, Tuple{ID}, Tuple{ID, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetT3), M}","page":"Reference","text":"FEMMShellT3FF(\n    integdomain::ID,\n    material::M,\n) where {ID<:IntegDomain{S} where {S<:FESetT3}, M}\n\nConstructor of the T3FF shell FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.associategeometry!-Tuple{FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp, FinEtools.NodalFieldModule.NodalField{Float64}}","page":"Reference","text":"associategeometry!(self::FEMMShellT3FFComp,  geom::NodalField{FFlt})\n\nAssociate geometry with the FEMM. \n\nIn this case it means evaluate the nodal normals.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.associategeometry!"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.inspectintegpoints-Union{Tuple{F}, Tuple{TI}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{Float64}, Vector{Int64}, F, Any}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{Float64}, Vector{Int64}, F, Any, Any}} where {TI<:Number, F<:Function}","page":"Reference","text":"inspectintegpoints(self::AbstractFEMMDeforLinear,\n  geom::NodalField{FFlt},  u::NodalField{TI},\n  dT::NodalField{FFlt},\n  felist::FIntVec,\n  inspector::F,  idat, quantity=:Cauchy;\n  context...) where {TI<:Number, F<:Function}\n\nInspect integration point quantities.\n\ngeom - reference geometry field\nu - displacement+rotation field\ndT - temperature difference field\nfelist - indexes of the finite elements that are to be inspected:    The fes to be included are: fes[felist].\ncontext    - structure: see the update!() method of the material.\ninspector - function with the signature       idat = inspector(idat, j, conn, x, out, loc);  where   idat - a structure or an array that the inspector may          use to maintain some state,  for instance minimum or maximum of          stress, j is the element number, conn is the element connectivity,          out is the output of the update!() method,  loc is the location          of the integration point in the reference configuration.\n\nReturn\n\nThe updated inspector data is returned.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.inspectintegpoints"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.make-Tuple{Any, Any}","page":"Reference","text":"make(integdomain, layup)\n\nMake a T3FFComp FEMM from the integration domain and a composite layup.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.make"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.mass-Union{Tuple{TI}, Tuple{A}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp, A, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}}} where {A<:FinEtools.AssemblyModule.AbstractSysmatAssembler, TI<:Number}","page":"Reference","text":"mass(self::FEMMShellT3FFComp,  assembler::A,  geom::NodalField{FFlt}, dchi::NodalField{TI}) where {A<:AbstractSysmatAssembler, TI<:Number}\n\nCompute the diagonal (lumped) mass matrix\n\nThe mass matrix can be expected to be non-singular.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.mass"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.num_normals-Tuple{FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp}","page":"Reference","text":"num_normals(self::FEMMShellT3FFComp)\n\nCompute the summary of the nodal normals.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.num_normals"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.stiffness-Union{Tuple{TI}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, TI<:Number}","page":"Reference","text":"stiffness(self::FEMMShellT3FFComp, assembler::ASS, geom0::NodalField{FFlt}, u1::NodalField{TI}, Rfield1::NodalField{TI}, dchi::NodalField{TI}) where {ASS<:AbstractSysmatAssembler, TI<:Number}\n\nCompute the material stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp","page":"Reference","text":"mutable struct FEMMShellT3FFComp{ID<:IntegDomain{S} where {S<:FESetT3}} <: AbstractFEMM\n\nType for the finite element modeling machine of the T3 triangular Flat-Facet shell with the Discrete Shear Gap technology and a consistent handling of the normals. This formulation is suitable for modelling of COMPOSITE (layered) materials. \n\nFor details about the homogeneous-shell refer to FinEtoolsFlexStructures.FEMMShellT3FFModule.FEMMShellT3FF.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp-Union{Tuple{ID}, Tuple{ID, FinEtoolsFlexStructures.CompositeLayupModule.CompositeLayup}} where ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetT3)","page":"Reference","text":"FEMMShellT3FFComp(\n    integdomain::ID,\n    layup::CompositeLayup,\n)  where {ID<:IntegDomain{S} where {S<:FESetT3}}\n\nConstructor of the T3FFComp shell FEMM. All elements use a single layup.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.FEMMShellT3FFComp"},{"category":"constant","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.__TRANSV_SHEAR_FORMULATION_AVERAGE_B","page":"Reference","text":"Formulation for the transverse shear stiffness which averages the strain-displacement matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.__TRANSV_SHEAR_FORMULATION_AVERAGE_B"},{"category":"constant","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule.__TRANSV_SHEAR_FORMULATION_AVERAGE_K","page":"Reference","text":"Formulation for the transverse shear stiffness which averages the stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule.__TRANSV_SHEAR_FORMULATION_AVERAGE_K"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.associategeometry!-Tuple{FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS, FinEtools.NodalFieldModule.NodalField{Float64}}","page":"Reference","text":"associategeometry!(self::FEMMShellQ4RS,  geom0::NodalField{FFlt})\n\nAssociate geometry with the FEMM. \n\nIn this case it means evaluate the nodal normals.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.associategeometry!"},{"category":"method","location":"man/man.html#FinEtools.FEMMBaseModule.inspectintegpoints-Union{Tuple{F}, Tuple{TI}, Tuple{FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{Float64}, Vector{Int64}, F, Any}, Tuple{FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{Float64}, Vector{Int64}, F, Any, Any}} where {TI<:Number, F<:Function}","page":"Reference","text":"inspectintegpoints(self::AbstractFEMMDeforLinear,\n  geom::NodalField{FFlt},  u::NodalField{TI},\n  dT::NodalField{FFlt},\n  felist::FIntVec,\n  inspector::F,  idat, quantity=:Cauchy;\n  context...) where {TI<:Number, F<:Function}\n\nInspect integration point quantities.\n\ngeom - reference geometry field\nu - displacement+rotation field\ndT - temperature difference field\nfelist - indexes of the finite elements that are to be inspected:    The fes to be included are: fes[felist].\ncontext    - structure: see the update!() method of the material.\ninspector - function with the signature       idat = inspector(idat, j, conn, x, out, loc);  where   idat - a structure or an array that the inspector may          use to maintain some state,  for instance minimum or maximum of          stress, j is the element number, conn is the element connectivity,          out is the output of the update!() method,  loc is the location          of the integration point in the reference configuration.\n\nReturn\n\nThe updated inspector data is returned.\n\n\n\n\n\n","title":"FinEtools.FEMMBaseModule.inspectintegpoints"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.make-Tuple{Any, Any, Any}","page":"Reference","text":"make(integdomain, mcsys, material)\n\nMake a Q4RS FEMM from the integration domain, a coordinate system to define the orientation of the normals, and a material.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.make"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.make-Tuple{Any, Any}","page":"Reference","text":"make(integdomain, material)\n\nMake a Q4RS FEMM from the integration domain,  and a material. Default isoparametric method for computing the normais is used.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.make"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.mass-Union{Tuple{TI}, Tuple{A}, Tuple{FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS, A, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}}} where {A<:FinEtools.AssemblyModule.AbstractSysmatAssembler, TI<:Number}","page":"Reference","text":"mass(self::FEMMShellQ4RS,  assembler::A,  geom::NodalField{FFlt}, dchi::NodalField{TI}) where {A<:AbstractSysmatAssembler, TI<:Number}\n\nCompute the diagonal (lumped) mass matrix.\n\nThe mass matrix can be expected to be non-singular.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.mass"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.num_normals-Tuple{FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS}","page":"Reference","text":"num_normals(self::FEMMShellQ4RS)\n\nCompute the summary of the nodal normals.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.num_normals"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.stiffness-Union{Tuple{TI}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{TI}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, TI<:Number}","page":"Reference","text":"stiffness(self::FEMMShellQ4RS, assembler::ASS, geom0::NodalField{FFlt}, u1::NodalField{TI}, Rfield1::NodalField{TI}, dchi::NodalField{TI}) where {ASS<:AbstractSysmatAssembler, TI<:Number}\n\nCompute the material stiffness matrix.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS","page":"Reference","text":"mutable struct FEMMShellQ4RS{ID<:IntegDomain{S} where {S<:FESetQ4}, T<:Real, CS<:CSys{T}, M} <: AbstractFEMM\n\nType for the finite element modeling machine of the Q4 quadrilateral  shell with the MITC (DSG) approach on the shear term and a consistent handling of the normals. \n\nAlso, the formulation is developed to correctly handle the coupling of twisting moments and transverse shear (such as in the twisted beam or the Raasch hook problems) by incorporating \"nodal\" normals.\n\nThe stabilization factor of the shear term of\n\n[2] Mikko Lyly, Rolf Stenberg and Teemu Vihinen, A stable bilinear element for the Reissner-Mindlin plate model Computer Methods in Applied Mechanics and Engineering 110 (1993) 343-357 \n\nis included to improve results on coarse meshes. Refer to expressions (3.12) and (3.13).\n\nThe formula for the element to nodal basis transformation is derived analogously  to the formulation of the robust flat-facet triangle, T3FF, but the contributions are  calculated differently: the transformation matrices are applied to the  strain-displacement matrices at the integration points.\n\nThe following features are incorporated to deal with nodal normals:\n\nNodal normals are averages of the normals of elements that meet at a node, or they  can be supplied as exact normals to a particular surface (sphere, cylinder, ...).\nA crease in the surface is taken into account. In that case the normal are not averaged across the crease. At the nodes along the crease every element uses the normal to its surface instead of the nodal normal.\n\nConfiguration:\n\nThese attributes of the FEMM can be set after it's been created.\n\ndrilling_stiffness_scale: multiplier of the generalized stiffness coefficient\nthreshold_angle: angle in degrees. If a nodal normal subtends angle bigger then this threshold, the nodal normal at that note is marked as invalid.\nmult_el_size: multiplier of the square of the element size, used to control transverse shear stiffness.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS-Union{Tuple{M}, Tuple{CS}, Tuple{T}, Tuple{ID}, Tuple{ID, CS, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetQ4), T<:Real, CS<:(FinEtools.CSysModule.CSys{T}), M}","page":"Reference","text":"FEMMShellQ4RS(\n    integdomain::ID,\n    mcsys::CSys,\n    material::M,\n) where {IntegDomain{S} where {S<:FESetQ4}, CS<:CSys, M}\n\nConstructor of the Q4RS shell FEMM.\n\nExample:\n\n    sfes = FESetShellQ4()\n    accepttodelegate(fes, sfes)\n    femm = formul.make(IntegDomain(fes, GaussRule(2, 2), thickness), mcsys, mater)\n\nHere the mcsys is used to compute the normals at the nodes, and the mater is  used to compute the material stiffness matrices. \n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS-Union{Tuple{M}, Tuple{ID}, Tuple{ID, M}} where {ID<:(FinEtools.IntegDomainModule.IntegDomain{S} where S<:FinEtools.FESetModule.FESetQ4), M}","page":"Reference","text":"FEMMShellQ4RS(\n    integdomain::ID,\n    material::M,\n) where {ID<:IntegDomain{S} where {S<:FESetQ4}, M}\n\nConstructor of the Q4RS shell FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellQ4RSModule.FEMMShellQ4RS"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMPointMassModule.mass-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMPointMassModule.FEMMPointMass, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, T<:Number, TI<:Number}","page":"Reference","text":"mass(\n    self::FEMMPointMass,\n    assembler::ASS,\n    geom0::NodalField{FFlt},\n    u1::NodalField{T},\n    Rfield1::NodalField{T},\n    dchi::NodalField{TI},\n) where {ASS<:AbstractSysmatAssembler,T<:Number,TI<:Number}\n\nCompute the consistent mass matrix\n\nThis is a general routine for the abstract linear-deformation  FEMM.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMPointMassModule.mass"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMPointMassModule.FEMMPointMass","page":"Reference","text":"mutable struct FEMMPointMass{ID<:IntegDomain} <: AbstractFEMM\n\nType for linear deformation finite element modeling machine.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMPointMassModule.FEMMPointMass"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.FEMMPointGroundedSpringModule.stiffness-Union{Tuple{TI}, Tuple{T}, Tuple{ASS}, Tuple{FinEtoolsFlexStructures.FEMMPointGroundedSpringModule.FEMMPointGroundedSpring, ASS, FinEtools.NodalFieldModule.NodalField{Float64}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{T}, FinEtools.NodalFieldModule.NodalField{TI}}} where {ASS<:FinEtools.AssemblyModule.AbstractSysmatAssembler, T<:Number, TI<:Number}","page":"Reference","text":"stiffness(\n    self::FEMMPointGroundedSpring,\n    assembler::ASS,\n    geom0::NodalField{FFlt},\n    u1::NodalField{T},\n    Rfield1::NodalField{T},\n    dchi::NodalField{TI},\n) where {ASS<:AbstractSysmatAssembler,T<:Number,TI<:Number}\n\nCompute the stiffness matrix\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMPointGroundedSpringModule.stiffness"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.FEMMPointGroundedSpringModule.FEMMPointGroundedSpring","page":"Reference","text":"mutable struct FEMMPointGroundedSpring{ID<:IntegDomain} <: AbstractFEMM\n\nType for finite element modeling machine for grounded springs.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMPointGroundedSpringModule.FEMMPointGroundedSpring"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.RotUtilModule.initial_Rfield-Tuple{Any}","page":"Reference","text":"initial_Rfield(fens)\n\nSet up initial rotation field (rotation matrices are all identities)\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.RotUtilModule.initial_Rfield"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.RotUtilModule.update_rotation_field!-Tuple{Any, Any}","page":"Reference","text":"update_rotation_field!(Rfield, dchi)\n\nUpdate rotation field by exponential incremental rotation. \n\n\n\n\n\n","title":"FinEtoolsFlexStructures.RotUtilModule.update_rotation_field!"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.TransformerModule.Layup2ElementAngle","page":"Reference","text":"Layup2ElementAngle{T}\n\nA callable object: computes the cosine and sine of the angle between the element frame and the layup reference direction.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.TransformerModule.Layup2ElementAngle"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.TransformerModule.TransformerQEQt","page":"Reference","text":"TransformerQEQt\n\nTransformerQEQt of square symmetric matrices.\n\nA callable object: computes Q * E * Q^T, where E a metric stiffness matrix, and Q is the transformation matrix. Both are assumed to be square.\n\nBuffers the intermediate result. Hence no allocation is incurred.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.TransformerModule.TransformerQEQt"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.TransformerModule.TransformerQEQt-Tuple{Any, Any}","page":"Reference","text":"(o::TransformerQEQt)(E, Q)\n\nPerform the transformation on the matrix E with the transformation matrix Q: Ebar = Q * E * Q^T.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.TransformerModule.TransformerQEQt"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.TransformerModule.TransformerQtEQ","page":"Reference","text":"TransformerQtEQ\n\nTransformerQtEQ of square symmetric matrices.\n\nA callable object: computes Q^T * E * Q, where E a symmetric matrix, and Q is the transformation matrix. Both are assumed to be square.\n\nBuffers the intermediate result. Hence no allocation is incurred.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.TransformerModule.TransformerQtEQ"},{"category":"method","location":"man/man.html#FinEtoolsFlexStructures.TransformerModule.TransformerQtEQ-Tuple{Any, Any}","page":"Reference","text":"(o::TransformerQtEQ)(E, Q)\n\nPerform the transformation on the matrix E with the transformation matrix Q: Ebar = Q^T * E * Q.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.TransformerModule.TransformerQtEQ"},{"category":"type","location":"man/man.html#FinEtoolsFlexStructures.AssemblyModule.SysmatAssemblerSparseCSRSymm","page":"Reference","text":"SysmatAssemblerSparseCSRSymm{A<:AbstractSysmatAssembler} <: AbstractSysmatAssembler\n\nAssembler for a symmetric square matrix  assembled from symmetric square matrices. The matrix is stored in the Compressed Sparse Row (CSR) format.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.AssemblyModule.SysmatAssemblerSparseCSRSymm"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FinEtoolsFlexStructures","page":"Reference","text":"FinEtoolsFlexStructures (C) 2020-2024, Petr Krysl\n\nFinEtools used for\n\nSimulations of large-displacement response of three-dimensional flexible-beam\n\nstructures. Linear static analysis, modal analysis, linear buckling analysis. Nonlinear statics and dynamics; \n\nSimulations of shell structures. Linear static analysis, modal analysis,\n\nexplicit dynamic analysis. Shells can be homogeneous or layered (laminated, composite).\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FinEtoolsFlexStructures"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.CompositeLayupModule","page":"Reference","text":"Module for working with composite layups.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CompositeLayupModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.CrossSectionModule","page":"Reference","text":"Module for working with cross-section properties of beam elements.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.CrossSectionModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.MeshFrameMemberModule","page":"Reference","text":"Module for construction of framed structures consisting of beam elements.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.MeshFrameMemberModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FESetL2BeamModule","page":"Reference","text":"Module for a 2-node beam element set.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetL2BeamModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FESetShellT3Module","page":"Reference","text":"Module for a 3-node shell element set.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetShellT3Module"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FESetShellQ4Module","page":"Reference","text":"Module for a 4-node shell element set.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FESetShellQ4Module"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMCorotBeamModule","page":"Reference","text":"Module for construction of the linear algebra matrix and vector quantities for the non-linear co-rotational beam.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMCorotBeamModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMLinBeamModule","page":"Reference","text":"Module for construction of the linear algebra matrix and vector quantities for the linear beam with eccentric connections to nodes.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMLinBeamModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMRITBeamModule","page":"Reference","text":"Module for construction of the linear algebra matrix and vector quantities for the linear Timoshenko beam based on reduced integration.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMRITBeamModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFModule","page":"Reference","text":"Module for operations on interiors of domains to construct system matrices and system vectors for linear homogenous shells using the robust flat-facet three-node triangular finite element (T3FF).\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMShellT3FFCompModule","page":"Reference","text":"Module for operations on interiors of domains to construct system matrices and system vectors for linear layered (composite) shells using the robust flat-facet three-node triangular finite element (T3FF).\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMShellT3FFCompModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMPointMassModule","page":"Reference","text":"Module for construction of the linear algebra matrix and vector quantities for the point masses.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMPointMassModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.FEMMPointGroundedSpringModule","page":"Reference","text":"Module for construction of the linear algebra matrix and vector quantities for the grounded springs.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.FEMMPointGroundedSpringModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.RotUtilModule","page":"Reference","text":"Module for utilities working with rotations in 3D space. \n\n\n\n\n\n","title":"FinEtoolsFlexStructures.RotUtilModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.TransformerModule","page":"Reference","text":"Module for geometric transformations of element matrices.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.TransformerModule"},{"category":"module","location":"man/man.html#FinEtoolsFlexStructures.AssemblyModule","page":"Reference","text":"Module for assemblers  of system matrices and vectors.\n\n\n\n\n\n","title":"FinEtoolsFlexStructures.AssemblyModule"}]
}
